<script setup lang="ts">import{useI18n}from'vue-i18n';import type{SubtitleConfig}from'@/types/subtitles';const model=defineModel<SubtitleConfig>({required:true});const{t}=useI18n();const colors=['backgroundColor','textColor','mutedColor','borderColor','shadowColor','outlineColor','errorColor'] as const</script>
<template><section class="form-section"><h2>{{t('subtitles.appearance.title')}}</h2><div class="form-grid"><label>{{t('subtitles.appearance.textOpacity')}}<input v-model.number="model.textOpacity" type="number" min="0.1" max="1" step="0.01"></label><label>{{t('subtitles.appearance.backgroundOpacity')}}<input v-model.number="model.backgroundOpacity" type="number" min="0" max="1" step="0.01"></label><label v-for="key in colors" :key="key" class="color-field">{{t(`subtitles.appearance.${key}`)}}<span><input v-model="model[key]" type="color"><input v-model="model[key]" type="text" pattern="#[0-9A-Fa-f]{6}"></span></label><label class="check"><input v-model="model.textShadow" type="checkbox">{{t('subtitles.appearance.shadow')}}</label><label>{{t('subtitles.appearance.shadowOffset')}}<input v-model.number="model.shadowOffset" type="number" min="1" max="8"></label><label class="check"><input v-model="model.textOutline" type="checkbox">{{t('subtitles.appearance.outline')}}</label><label>{{t('subtitles.appearance.outlineWidth')}}<input v-model.number="model.outlineWidth" type="number" min="0" max="8"></label></div></section></template>
